import{_ as e,o as r,c as a,a2 as o}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"OpenCode","description":"","frontmatter":{"title":"OpenCode","category":"agents","status":"complete"},"headers":[],"relativePath":"research/agents/opencode/index.md","filePath":"research/agents/opencode/index.md"}'),n={name:"research/agents/opencode/index.md"};function i(s,t,d,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="opencode" tabindex="-1">OpenCode <a class="header-anchor" href="#opencode" aria-label="Permalink to &quot;OpenCode&quot;">​</a></h1><blockquote><p>Open-source Go-based CLI coding agent with a rich terminal UI, built by Anomaly Innovations (now maintained by the Charm team as &quot;Crush&quot;).</p></blockquote><h2 id="what-is-opencode" tabindex="-1">What Is OpenCode? <a class="header-anchor" href="#what-is-opencode" aria-label="Permalink to &quot;What Is OpenCode?&quot;">​</a></h2><p>OpenCode is a <strong>Go-based terminal coding agent</strong> that provides an interactive TUI (Terminal User Interface) for AI-assisted software development. It supports multiple LLM providers (Anthropic, OpenAI, Google Gemini, AWS Bedrock, Groq, Azure, OpenRouter, GitHub Copilot, xAI, and local models) and includes a comprehensive set of coding tools—file editing, shell execution, code search, LSP integration, and sub-agent delegation.</p><p>Unlike many coding agents built in Python or TypeScript, OpenCode is written entirely in <strong>Go</strong> using the <a href="https://github.com/charmbracelet/bubbletea" target="_blank" rel="noreferrer">Bubble Tea</a> TUI framework from Charm. This gives it a distinctive niche: fast startup, a single static binary, and a polished terminal-native experience with vim-like keybindings.</p><h2 id="who-built-it" tabindex="-1">Who Built It <a class="header-anchor" href="#who-built-it" aria-label="Permalink to &quot;Who Built It&quot;">​</a></h2><p>OpenCode was created by <strong>Anomaly Innovations</strong> (anomalyco). The project was originally authored by Jay V (GitHub: jayair), who is also known for creating SST (Serverless Stack). The project has since been <strong>archived</strong> and continued under the name <strong><a href="https://github.com/charmbracelet/crush" target="_blank" rel="noreferrer">Crush</a></strong> by the original author and the Charm team (charmbracelet).</p><h2 id="why-it-matters" tabindex="-1">Why It Matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why It Matters&quot;">​</a></h2><ol><li><p><strong>Go in the agent space</strong>: Most coding agents are Python/TypeScript. OpenCode demonstrates that Go is a viable language for building agentic systems, with advantages in binary distribution, startup time, and concurrency.</p></li><li><p><strong>TUI-first design</strong>: While most agents are CLI-first with basic text output, OpenCode built a full Bubble Tea TUI with session management, model switching dialogs, permission dialogs, file diff views, and vim-like editor integration.</p></li><li><p><strong>Provider abstraction</strong>: Clean multi-provider support with a unified <code>Provider</code> interface, supporting 10+ providers through native SDKs (not just OpenAI-compatible APIs).</p></li><li><p><strong>Community adoption</strong>: The website claims 120K+ GitHub stars, 800+ contributors, and 5M+ monthly developers (across the broader OpenCode/Crush ecosystem).</p></li></ol><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td>Language</td><td>Go 1.24</td></tr><tr><td>TUI Framework</td><td>Bubble Tea (charmbracelet/bubbletea)</td></tr><tr><td>Styling</td><td>Lip Gloss (charmbracelet/lipgloss)</td></tr><tr><td>Database</td><td>SQLite (ncruces/go-sqlite3 via Wasm)</td></tr><tr><td>Migrations</td><td>Goose (pressly/goose)</td></tr><tr><td>SQL Generation</td><td>sqlc</td></tr><tr><td>CLI Framework</td><td>Cobra (spf13/cobra)</td></tr><tr><td>Config</td><td>Viper (spf13/viper)</td></tr><tr><td>LLM SDKs</td><td>anthropic-sdk-go, openai-go, google/genai</td></tr><tr><td>MCP</td><td>mark3labs/mcp-go</td></tr><tr><td>Markdown</td><td>Glamour (charmbracelet/glamour)</td></tr><tr><td>Themes</td><td>Catppuccin</td></tr></tbody></table><h2 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to &quot;Current Status&quot;">​</a></h2><ul><li><strong>Archived</strong>: The opencode-ai/opencode repository is archived</li><li><strong>Successor</strong>: Continued as <a href="https://github.com/charmbracelet/crush" target="_blank" rel="noreferrer">Crush</a> under Charm</li><li><strong>License</strong>: MIT</li><li><strong>Last active version</strong>: v0.x (early development)</li></ul><h2 id="benchmark-performance" tabindex="-1">Benchmark Performance <a class="header-anchor" href="#benchmark-performance" aria-label="Permalink to &quot;Benchmark Performance&quot;">​</a></h2><ul><li><strong>Terminal-Bench 2.0</strong>: Rank #50 (Claude Opus 4.5, 51.7%)</li><li><strong>Note</strong>: As an early-stage project, benchmark scores reflect its nascent tooling maturity rather than architectural limitations</li></ul><h2 id="key-files-for-understanding-the-codebase" tabindex="-1">Key Files for Understanding the Codebase <a class="header-anchor" href="#key-files-for-understanding-the-codebase" aria-label="Permalink to &quot;Key Files for Understanding the Codebase&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>internal/llm/agent/agent.go</code></td><td>Core agentic loop</td></tr><tr><td><code>internal/llm/agent/tools.go</code></td><td>Tool registration per agent type</td></tr><tr><td><code>internal/llm/provider/provider.go</code></td><td>Provider abstraction interface</td></tr><tr><td><code>internal/llm/tools/tools.go</code></td><td>Tool interface definition</td></tr><tr><td><code>internal/tui/tui.go</code></td><td>Main TUI application</td></tr><tr><td><code>internal/app/app.go</code></td><td>Application initialization</td></tr><tr><td><code>internal/session/session.go</code></td><td>Session management</td></tr><tr><td><code>internal/message/message.go</code></td><td>Message persistence</td></tr><tr><td><code>internal/pubsub/broker.go</code></td><td>Generic pub/sub event system</td></tr><tr><td><code>internal/permission/permission.go</code></td><td>Permission request/grant flow</td></tr></tbody></table>',17)])])}const u=e(n,[["render",i]]);export{g as __pageData,u as default};
